#include<bits/stdc++.h>
using namespace std;
char s1[100010],s2[100010],t1[100010],t2[100010];
int id1[100010],id2[100010],cnt0_s1[100010],cnt1_s1[100010],cnt0_s2[100010],cnt1_s2[100010];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n;
        scanf("%d%s%s%s%s",&n,s1+1,s2+1,t1+1,t2+1);
        int tot1=0,tot2=0;
        memset(id1,0,sizeof(id1));
        memset(id2,0,sizeof(id2));
        memset(cnt0_s1,0,sizeof(cnt0_s1));
        memset(cnt1_s1,0,sizeof(cnt1_s1));
        memset(cnt0_s1,0,sizeof(cnt0_s2));
        memset(cnt1_s1,0,sizeof(cnt1_s2));
        for(int i=1;i<=n;i++)
        {
            if(t1[i]=='1'&&t1[i-1]=='1')
            {
                id1[i]=id1[i-1];
            }
            else
            {
                id1[i]=++tot1;
            }
            if(s1[i]=='1')
            {
                cnt1_s1[id1[i]]++;
            }
            else
            {
                cnt0_s1[id1[i]]++;
            }
            if(t2[i]=='1'&&t2[i-1]=='1')
            {
                id2[i]=id2[i-1];
            }
            else
            {
                id2[i]=++tot2;
            }
            if(s2[i]=='1')
            {
                cnt1_s2[id2[i]]++;
            }
            else
            {
                cnt0_s2[id2[i]]++;
            }
            // printf("id1[%d]=%d(cnt: 0 %d   1 %d) id2[%d]=%d(cnt: 0 %d   1 %d)\n",i,id1[i],cnt0_s1[id1[i]],cnt1_s1[id1[i]],i,id2[i],cnt0_s2[id2[i]],cnt1_s2[id2[i]]);
        }
        int ans=0;
        for(int i=1;i<=n;i++)
        {
            if(cnt0_s1[id1[i]]&&cnt0_s2[id2[i]])
            {
                ans++;
                cnt0_s1[id1[i]]--;
                cnt0_s2[id2[i]]--;
            }
            else if(cnt1_s1[id1[i]]&&cnt1_s2[id2[i]])
            {
                ans++;
                cnt1_s1[id1[i]]--;
                cnt1_s2[id2[i]]--;
            }
            else if(cnt1_s1[id1[i]])
            {
                cnt1_s1[id1[i]]--;
                cnt0_s2[id2[i]]--;
            }
            else
            {
                cnt0_s1[id1[i]]--;
                cnt1_s2[id2[i]]--;
            }
        }
        printf("%d\n",ans);
    }
    return 0;
}
